class FileWordIterator implements Iterator<String> {

    private final BufferedReader fileBufferedReader;
    private final Queue<String> words = new LinkedList<>();

    public FileWordIterator(String filePath) throws IOException {
        Path path = Paths.get(filePath);
        fileBufferedReader = Files.newBufferedReader(path);
    }

    @Override
    public boolean hasNext() {
        if (words.size() > 0) {
            return true;
        }
        try {
            do {
                String line = fileBufferedReader.readLine();
                if (line == null) {
                    fileBufferedReader.close();
                    return false;
                }
                if (line.length() > 0) {
                    words.addAll(Arrays.asList(line.split("\\s")));
                }
            } while (words.size() == 0);

        } catch (IOException e) {
            return false;
        }

        return true;
    }

    @Override
    public String next() {
        return words.remove();
    }
}
