import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.util.Iterator;
import java.util.LinkedList;
import java.util.Queue;

public class WordIterator implements Iterator<String> {
    private Queue<File> filesQueue = new LinkedList<>();
    private BufferedReader reader;
    private String[] currentWords = new String[0];
    private int wordIndex = 0;

    public WordIterator(File file) {
        if (file.isDirectory()) {
            // Add all files in the directory to the queue
            addFilesFromDirectory(file);
        } else {
            // Add a single file to the queue
            filesQueue.add(file);
        }
        moveToNextFile();
    }

    private void addFilesFromDirectory(File directory) {
        File[] files = directory.listFiles();
        if (files != null) {
            for (File f : files) {
                if (f.isDirectory()) {
                    addFilesFromDirectory(f); // Recursively add files from subdirectories
                } else if (f.isFile()) {
                    filesQueue.add(f);
                }
            }
        }
    }

    @Override
    public boolean hasNext() {
        // Check if there are more words in the current file
        while (wordIndex >= currentWords.length) {
            if (!moveToNextLine()) {
                if (!moveToNextFile()) {
                    return false; // No more files or words
                }
            }
        }
        return true;
    }

    @Override
    public String next() {
        if (hasNext()) {
            return currentWords[wordIndex++];
        }
        return null;
    }

    private boolean moveToNextFile() {
        closeCurrentReader();
        if (!filesQueue.isEmpty()) {
            File file = filesQueue.poll();
            try {
                reader = new BufferedReader(new FileReader(file));
            } catch (IOException e) {
                e.printStackTrace();
                return moveToNextFile(); // Skip the problematic file
            }
            return moveToNextLine();
        }
        return false;
    }

    private boolean moveToNextLine() {
        try {
            String line;
            while ((line = reader.readLine()) != null) {
                currentWords = line.split("\\s+");
                wordIndex = 0;
                if (currentWords.length > 0) {
                    return true;
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
        return false;
    }

    private void closeCurrentReader() {
        if (reader != null) {
            try {
                reader.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }
}
